import{c as o,Q as t,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Anthropic Economic Index Report: Uneven Geographic and Enterprise AI Adoption","description":"","frontmatter":{"title":"Anthropic Economic Index Report: Uneven Geographic and Enterprise AI Adoption","authors":"Ruth Appel, Peter McCrory, Alex Tamkin, Miles McCain, Tyler Neylon, Michael Stern","published":"2025-11-19T00:00:00.000Z","source":"https://arxiv.org/abs/2511.15080"},"headers":[],"relativePath":"research/papers/2025-11-19-anthropic-economic-index-geographic-adoption-2511-15080.md","filePath":"research/papers/2025-11-19-anthropic-economic-index-geographic-adoption-2511-15080.md","lastUpdated":1779901665000}'),n={name:"research/papers/2025-11-19-anthropic-economic-index-geographic-adoption-2511-15080.md"};function i(s,e,c,l,p,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="anthropic-economic-index-report-uneven-geographic-and-enterprise-ai-adoption" tabindex="-1">Anthropic Economic Index Report: Uneven Geographic and Enterprise AI Adoption <a class="header-anchor" href="#anthropic-economic-index-report-uneven-geographic-and-enterprise-ai-adoption" aria-label="Permalink to &quot;Anthropic Economic Index Report: Uneven Geographic and Enterprise AI Adoption&quot;">​</a></h1><p><strong>Authors</strong>: Ruth Appel, Peter McCrory, Alex Tamkin, Miles McCain, Tyler Neylon, Michael Stern (Anthropic) <strong>Published</strong>: November 19, 2025 <strong>Source</strong>: <a href="https://arxiv.org/abs/2511.15080" target="_blank" rel="noreferrer">https://arxiv.org/abs/2511.15080</a><strong>arXiv ID</strong>: 2511.15080 <strong>Categories</strong>: econ.GN, cs.CY <strong>Data</strong>: Open-sourced for academic/policy research <strong>Dataset</strong>: 1M Claude.ai conversations + 1M API transcripts, 150+ countries</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Second Anthropic Economic Index report documenting Claude usage patterns over time, across 150+ countries and U.S. states, and among API-deploying businesses. Uses privacy-preserving analysis of 2 million total transcripts. Key finding: <strong>users increasingly delegate more autonomy to Claude</strong>, with directive task delegation rising from 27% to 39% over eight months. Geographic concentration strongly favors high-income nations.</p><hr><h2 id="key-findings" tabindex="-1">Key Findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key Findings&quot;">​</a></h2><h3 id="_1-rising-autonomy-delegation" tabindex="-1">1. Rising Autonomy Delegation <a class="header-anchor" href="#_1-rising-autonomy-delegation" aria-label="Permalink to &quot;1. Rising Autonomy Delegation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Period</th><th>Directive Task Delegation Rate</th></tr></thead><tbody><tr><td>~Early 2025</td><td>27%</td></tr><tr><td>~Late 2025</td><td><strong>39%</strong></td></tr><tr><td>Delta</td><td>+12 percentage points over 8 months</td></tr></tbody></table><p>Users are progressively entrusting Claude with more autonomous, complete task execution rather than step-by-step collaboration.</p><h3 id="_2-geographic-concentration" tabindex="-1">2. Geographic Concentration <a class="header-anchor" href="#_2-geographic-concentration" aria-label="Permalink to &quot;2. Geographic Concentration&quot;">​</a></h3><p><strong>High-income nations are significantly overrepresented</strong> in Claude usage relative to their working-age population share.</p><ul><li>Usage concentrated in wealthy countries</li><li>150+ countries represented, but distribution heavily skewed</li><li>Local economic factors influence: <ul><li>Which topics users bring to Claude</li><li>Preferred collaboration modes (automation vs. augmentation)</li><li>Task categories most commonly requested</li></ul></li></ul><h3 id="_3-enterprise-api-adoption-patterns" tabindex="-1">3. Enterprise API Adoption Patterns <a class="header-anchor" href="#_3-enterprise-api-adoption-patterns" aria-label="Permalink to &quot;3. Enterprise API Adoption Patterns&quot;">​</a></h3><p>API customers use Claude for <strong>specialized task automation</strong> distinct from consumer (Claude.ai) patterns:</p><ul><li>More directive/automative usage vs. consumer augmentative usage</li><li>Specialized domain focus rather than general-purpose queries</li></ul><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p><strong>Dataset</strong>:</p><ul><li>1 million Claude.ai consumer conversations</li><li>1 million API transcripts (business deployments)</li></ul><p><strong>Tool</strong>: Clio (privacy-preserving analysis — same framework as Economic Tasks paper 2503.04761)</p><p><strong>Geographic scope</strong>: 150+ countries, all U.S. states</p><p><strong>Longitudinal</strong>: Tracks changes over time (first Anthropic Economic Index report was earlier in 2025)</p><hr><h2 id="connection-to-prior-work" tabindex="-1">Connection to Prior Work <a class="header-anchor" href="#connection-to-prior-work" aria-label="Permalink to &quot;Connection to Prior Work&quot;">​</a></h2><p>Builds on the &quot;Which Economic Tasks are Performed with AI?&quot; paper (2503.04761):</p><ul><li>That paper: task-level analysis (what tasks Claude performs)</li><li>This paper: geographic/temporal/enterprise analysis (who uses Claude and how usage evolves)</li></ul><p>Together they form the <strong>Anthropic Economic Index</strong> — a framework for empirically tracking AI&#39;s economic integration.</p><hr><h2 id="open-data" tabindex="-1">Open Data <a class="header-anchor" href="#open-data" aria-label="Permalink to &quot;Open Data&quot;">​</a></h2><p>Researchers open-sourced underlying data for academic and policy research, enabling independent replication and extension of findings.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Contextualizes Claude usage patterns at the macro level:</p><ol><li><strong>39% directive delegation (up from 27%)</strong>: The trend toward full task autonomy validates workspace design choices in <code>autoresearch</code> (fully autonomous loop) and <code>implementer</code> agent (full task delegation) — these match where users are naturally moving</li><li><strong>Geographic concentration in high-income nations</strong>: Workspace design for English-language, high-technical-sophistication users is consistent with the actual user base</li><li><strong>API = specialized automation</strong>: The workspace itself is an API deployment — enterprise-style automative patterns are correct baseline assumption, not consumer-style exploratory usage</li><li><strong>Longitudinal tracking</strong>: This paper validates that tracking usage patterns over time (as <code>claude-progress.json</code> does at session level) is useful — macro trends mirror micro session trends</li></ol>',35)])])}const u=o(n,[["render",i]]);export{g as __pageData,u as default};
